  'kunming/ricenoodle': ('過橋米線', '熱々のスープに細い米麺をくぐらせて食べる過橋米線は、雲南省を代表する名物料理です。'),
  'jinan/spring': ('泉城', '街の至る所から72もの名泉が湧き出ることから、済南は「泉の街」と呼ばれています。'),
  'jinan/daminglake': ('大明湖', '柳と蓮に囲まれたこの美しい湖は、街の泉から流れ込む水によって満たされています。'),
  'jinan/buddhamountain': ('千仏山', '山の斜面に数百もの仏像が彫られたこの山は、多くの参拝者が訪れる聖地です。'),
  'jinan/poet': ('李清照', '中国史上最も偉大な女性詩人と称される李清照は、この泉の街で生まれました。'),
  'ningbo/library': ('天一閣', '450年以上の歴史を持つ天一閣は、アジアで現存する最古の私立図書館です。'),
  'ningbo/port': ('寧波舟山港', '寧波舟山港は、貨物取扱量において世界で最も忙しい港として知られています。'),
  'ningbo/tangyuan': ('湯円', '黒ごま餡が入ったもちもちの湯円は、この街を代表する甘い名物です。'),
  'ningbo/seafood': ('海鮮料理', '東シナ海で獲れるイシモチやカニなどの新鮮な魚介類が、地元の食卓を支えています。'),
  'shijiazhuang/bridge': ('趙州橋', '1400年の歴史を誇るこの石造りのアーチ橋は、世界最古の開放型スパンドレル橋です。'),
  'shijiazhuang/clifftemple': ('蒼岩山', '断崖絶壁の間に架かる橋上の寺院は、数多くの映画のロケ地としても有名です。'),
  'shijiazhuang/redbase': ('西柏坡', '「新中国」の建国計画が練られたこの村は、中国の革命ゆかりの地を巡る「レッドツーリズム」の聖地として知られています。'),
  'shijiazhuang/pharma': ('医薬の街', '中国最大級の製薬拠点を擁するこの街は、抗生物質の生産地として重要な役割を担っています。'),
  'taiyuan/jincitemple': ('晋祠', '3000年の歴史を持つ彫像や湧水が残る晋祠は、中国北部で最も優美な寺院庭園の一つです。'),
  'taiyuan/coalcart': ('石炭の都', '山西省の豊富な石炭資源は中国のエネルギーを支えており、太原はその富が集まる中心地です。'),
  'taiyuan/vinegar': ('山西老陳酢', '熟成された黒酢である「老陳酢」は、山西料理の味を引き立てる欠かせない調味料です。'),
  'taiyuan/twinpagoda': ('双塔', '明代に建てられた二つの八角形の塔が並び立つ姿は、この街のシンボルとして親しまれています。'),
  'hohhot/lamatemple': ('大召寺', '銀の仏像で有名なこのチベット仏教寺院は、フフホト市民の心の拠り所となっています。'),
  'hohhot/dairy': ('乳業の都', '中国を代表する乳製品メーカーが誕生したこの街は、「ミルクの都」として広く知られています。'),
  'hohhot/wrestling': ('モンゴル相撲', 'ナーダム祭のハイライトであるモンゴル相撲は、草原の男たちの力強さを象徴する伝統競技です。'),
  'hohhot/prairie': ('草原', '街を一歩出れば、馬や家畜が群れをなして暮らす広大なモンゴルの草原が広がっています。'),
  'sanya/resortbeach': ('亜龍湾', 'パウダーサンドの砂浜とエメラルドグリーンの海が広がる亜龍湾は、「中国のハワイ」と称されるリゾート地です。'),
  'sanya/guanyin': ('南山海上観音聖像', '海上にそびえ立つ高さ108メートルの観音像は、世界最大級の観音像として圧倒的な存在感を放っています。'),
  'sanya/diving': ('ダイビング', '一年を通して暖かく透明度の高い海とサンゴ礁に恵まれた三亜は、ダイバーたちの楽園です。'),
  'sanya/coconutdrink': ('ココナッツジュース', '南国の木々から採れる新鮮なココナッツジュースは、島を訪れる人々の喉を潤す定番の飲み物です。'),
  'yangzhou/slenderlake': ('痩西湖', '柳が揺れ、白い橋が架かる痩西湖の風景は、まるで一枚の絵画のように優美で情緒にあふれています。'),
  'yangzhou/friedrice': ('揚州チャーハン', 'エビや卵を黄金色のご飯と炒め合わせた、世界的に有名な定番料理です。'),
  'yangzhou/morningtea': ('早茶', '点心とともにお茶を楽しむ優雅な朝食は、揚州の伝統的な習慣です。'),
  'yangzhou/gegarden': ('個園', '四季を表現した石組みの庭園は、中国古典庭園の傑作として知られています。'),
  'weihai/navalisland': ('劉公島', '北洋艦隊の拠点であったこの島は、中国の近代海軍史を今に伝える場所です。'),
  'weihai/swan': ('スワンレイク', '冬になるとシベリアから数百羽のコハクチョウが飛来し、美しい姿を見せてくれます。'),
  'weihai/seacucumber': ('ナマコ', '冷たく澄んだ海で育ったナマコは、この街で最も珍重されている海産物です。'),
  'weihai/cape': ('成山頭', '中国の最東端に位置するこの岬は、国内で最も早く朝日が昇る場所として有名です。'),
  'handan/taichi': ('太極拳', '楊式や武式の発祥地である広府古城は、太極拳の聖地として知られています。'),
  'handan/congtai': ('叢台', '古代の趙国から伝わるこの高台は、2000年以上の歴史を見守り続けてきました。'),
  'handan/idiom': ('成語の街', '1500以上の中国語の成語が生まれた場所であり、邯鄲は「成語の街」と呼ばれています。'),
  'handan/ciporcelain': ('磁州窯', '白地に黒の絵付けが特徴的な磁州窯の陶磁器は、中国民窯の代表格です。'),
  'daqing/oilpump': ('大慶油田', '中国最大の油田であり、広大な敷地には無数のポンプジャックが並んでいます。'),
  'daqing/oilworker': ('鉄人', '石油労働者の英雄である王進喜の不屈の精神は、この街の礎となっています。'),
  'daqing/reedlake': ('湿地帯', '油田の中に広がる広大な葦の湖は、ツルや白鳥たちの憩いの場となっています。'),
  'daqing/hotspring': ('温泉', '地下から湧き出るミネラル豊富な温泉は、北国の厳しい寒さを癒やしてくれます。'),
  'zibo/bbq': ('淄博バーベキュー', '小さなコンロで焼いた串焼きを薄い皮で巻いて食べる、中国全土で一大ブームを巻き起こしたグルメです。'),
  'zibo/cuju': ('蹴鞠', '世界最古のサッカーと言われる「蹴鞠」は、かつて斉の都であった臨淄で盛んに行われていました。'),
  'zibo/ceramic': ('淄博陶磁器', '千年の歴史を持つ窯元が点在する、中国北部を代表する陶磁器の産地です。'),
  'zibo/glass': ('瑠璃', '色鮮やかなガラスを溶かして手作りされる「瑠璃」は、光を浴びて美しく輝く伝統工芸品です。'),
  'taian/mounttai': ('泰山', '五岳独尊と称される聖なる山で、歴代皇帝が天に祈りを捧げる封禅の儀式を行った場所です。'),
  'taian/sunrise': ('泰山の日の出', '雲海から昇る壮大な日の出を拝むことは、泰山登山の最大の醍醐味です。'),
  'taian/stonesteps': ('十八盤', '山頂まで続く7,000段もの石段は、参拝者にとって心身を鍛える試練の道となっています。'),
  'taian/daitemple': ('岱廟', '泰山の麓にある壮大な寺院で、皇帝たちが泰山での儀式に備えて身を清めた場所です。'),
  'lianyungang/monkey': ('花果山', '『西遊記』に登場する孫悟空の故郷とされる山で、多くの観光客が訪れる名所です。'),
  'lianyungang/seaport': ('連雲港港', 'シルクロードの東の玄関口であり、ユーラシア・ランドブリッジの太平洋側の起点となる港です。'),
  'lianyungang/mountain': ('雲台山', '険しい峰々と豊かな森に覆われた、江蘇省で最も高い山です。'),
  'lianyungang/crystal': ('水晶の街', '近隣の東海県は、世界最大級の水晶取引市場として知られています。'),
  'maanshan/libai': ('李白の墓', '中国最大の詩人である李白が晩年を過ごし、その生涯を閉じた地として知られています。'),
  'maanshan/steel': ('鉄鋼の街', '馬鋼集団の製鉄所を中心に発展し、中国有数の鉄鋼生産拠点となった街です。'),
  'maanshan/rivercliff': ('采石磯', '長江に突き出す断崖絶壁で、詩人・李白にまつわる伝説が残る風光明媚な場所です。'),
  'maanshan/moonwine': ('李白の月と酒', '李白の詩に詠まれた月と酒は、今も川辺の祭りで大切に受け継がれています。'),
  'longyan/tulou': ('永定土楼', '丘陵地帯に点在する巨大な円形の客家集合住宅は、ユネスコ世界遺産にも登録されています。'),
  'longyan/redmeeting': ('古田会議', '紅軍の進むべき道を決定づけた歴史的な会議が、この村で開催されました。'),
  'longyan/hakka': ('客家文化', '北から移住してきた客家の人々は、この山あいの地で独自の言語や食文化を守り続けています。'),
  'longyan/mountain': ('冠豸山', '赤い断崖と澄んだ池が美しいこの山は、福建省南部における自然の宝石と称されています。'),
  'sanming/danxia': ('泰寧丹霞', '赤い断崖と峡谷が広がるこのユネスコ世界ジオパークは、まるで天から落ちてきた石の迷宮のようです。'),
  'sanming/shaxian': ('沙県小吃', '手頃な価格のワンタンや和え麺で知られる沙県小吃は、今や中国全土で愛されています。'),
  'sanming/forest': ('緑の都', '中国で最も森林率が高い三明市は、澄んだ空気と緑豊かな山々に囲まれています。'),
  'sanming/goldenlake': ('金湖', '丹霞地形の断崖の間に広がるこの湖は、遊覧船に乗ってゆったりと散策することができます。'),
  'ningde/mudflat': ('霞浦の干潟', '潮の満ち引きで表情を変えるきらめく干潟は、世界で最も写真に収められている海岸の一つです。'),
  'ningde/whitetea': ('福鼎白茶', '産毛に覆われた芽を乾燥させて作る白茶は、熟成させるほどに価値が高まる貴重なお茶です。'),
  'ningde/taimu': ('太姥山', '海を見下ろす花崗岩の奇峰と洞窟が連なるこの山は、「海上の仙都」と称えられています。'),
  'ningde/croaker': ('イシモチ', '穏やかな湾内で養殖される大型のイシモチは、この街が誇る海の宝物です。'),
  'shaoguan/redcliff': ('丹霞山', '「丹霞地形」の語源となったこの赤い岩山は、独特の形をした岩柱で有名です。'),
  'shaoguan/chantemple': ('南華寺', '禅宗の第六祖である慧能ゆかりの寺院であり、禅宗の聖地として知られています。'),
  'shaoguan/ancestor': ('珠璣巷', '数百万人の華南出身者がルーツを辿る、歴史ある移住の拠点です。'),
  'shaoguan/yaodance': ('ヤオ族', '山間部の村々に暮らすヤオ族は、色鮮やかな民族衣装と伝統的な太鼓踊りで知られています。'),
  'zhanjiang/oyster': ('湛江牡蠣', '温暖な南の海で育った身の詰まった牡蠣を炭火で焼いた、絶品のグルメです。'),
  'zhanjiang/navy': ('軍港', '南海艦隊の拠点であり、中国南部の海の玄関口として重要な役割を担っています。'),
  'zhanjiang/mangrove': ('マングローブ林', '中国最大規模のマングローブ林が広がり、潮間帯にはサギやカニなどの多様な生き物が生息しています。'),
  'zhanjiang/donghai': ('東海島', '長い砂浜と安定した風に恵まれ、海水浴やサーフィンを楽しむ人々で賑わう島です。'),
  'maoming/lychee': ('ライチの都', '中国最大のライチ生産地であり、かつては皇帝にも献上された歴史ある土地です。'),
  'maoming/refinery': ('石油化学コンビナート', '中国南部最大級の製油所を擁し、この街の産業を力強く支えています。'),
  'maoming/ladyxian': ('冼夫人', '嶺南地方を統一した英雄として、千年以上もの間、地元の人々に敬愛され続けています。'),
  'maoming/seaside': ('中国第一灘', '「中国第一のビーチ」と称される美しい海岸線で、家族連れが黄金色の砂浜を楽しめます。'),
  'zhaoqing/sevenstar': ('七星岩', '湖から突き出す7つの石灰岩の峰は、「広東の桂林」と称される絶景です。'),
  'zhaoqing/inkstone': ('端渓硯', '書道の「文房四宝」の一つに数えられる端渓硯は、千年以上前からこの地で彫り続けられています。'),
  'zhaoqing/dinghu': ('鼎湖山', '中国初の自然保護区であり、豊かな熱帯雨林と滝が広がる天然の酸素バーです。'),
  'zhaoqing/songwall': ('宋代城壁', '宋代の姿をそのままに残す城壁が、古い肇慶の街を歴史の輪のように囲んでいます。'),
  'huizhou/westlake': ('恵州西湖', '詩人・蘇軾が愛したこの湖は、柳の木と堤が織りなす詩情豊かな風景が魅力です。'),
  'huizhou/luofu': ('羅浮山', '道教の聖地であり、薬草の宝庫としても知られる「嶺南第一山」と称される名峰です。'),
  'huizhou/alchemy': ('葛洪の錬丹術', '錬丹術師であり医師でもあった葛洪が、この山で伝統医学の基礎を築きました。'),
  'huizhou/xunliao': ('巽寮湾', '透き通った海と白い砂浜が広がる、南海岸の静かなリゾート地です。'),
  'meizhou/weilongwu': ('囲龍屋', '「世界の客家人の都」と呼ばれる梅州は、馬蹄形の伝統住宅「囲龍屋」で有名です。'),
  'meizhou/saltchicken': ('塩焗鶏', '熱した塩の中に鶏を埋めて焼き上げる、肉の旨味が凝縮された客家料理の代表格です。'),
  'meizhou/football': ('サッカーの郷', '中国サッカーの聖地として知られ、長年にわたり多くのスター選手を輩出しています。'),
  'meizhou/plum': ('梅の花', '「梅」の名を冠するこの街では、冬になると美しい梅の花が街を彩ります。'),
  'jiangmen/diaolou': ('開平楼閣', '海外から帰国した華僑によって建てられた多層階の要塞建築で、世界遺産にも登録されています。'),
  'jiangmen/qiaoxiang': ('華僑の郷', '数百万人の華僑の故郷であり、東洋と西洋の文化が融合した独特の景観が魅力です。'),
  'jiangmen/chenpi': ('陳皮', '新会産のミカンの皮を熟成させた陳皮は、料理のスパイスとしても貴重な漢方薬としても重宝されています。'),
  'jiangmen/birds': ('小鳥天堂', '一本の巨大なガジュマルの木が森となり、数万羽のサギが暮らす楽園となっています。'),
  'yangjiang/knife': ('刃物の都', '何世紀にもわたる鍛冶の伝統を受け継ぎ、中国国内の多くの包丁がこの地で生産されています。'),
  'yangjiang/shipwreck': ('南海一号', '海のシルクロードを辿った宋代の沈没船が、当時の財宝とともに水中博物館で展示されています。'),
  'yangjiang/hailing': ('海陵島', '美しいビーチと波が魅力の、広東省で最も人気のあるリゾートアイランドです。'),
  'yangjiang/kite': ('凧の街', '濰坊と並ぶ中国の「凧の都」として知られ、秋になると空を色鮮やかな凧が埋め尽くします。'),
  'qingyuan/rafting': ('清遠ラフティング', '清遠は急流が流れる山々に囲まれており、中国におけるラフティングの聖地として知られています。'),
  'qingyuan/chicken': ('清遠鶏', '骨が細く旨味が強い清遠鶏は、広東料理の食卓で最も重宝される高級食材です。'),
  'qingyuan/hotspring': ('温泉', '山あいの谷から湧き出るミネラル豊富な温泉は、週末の癒やしの旅先として人気を集めています。'),
  'qingyuan/yaoterrace': ('ヤオ族の棚田', '連南のヤオ族が山の斜面を切り開いて造った棚田は、何世紀にもわたる人々の勤勉な営みの結晶です。'),
  'chaozhou/guangjibridge': ('広済橋', '中央部が船で開閉する珍しい構造を持つこの古橋は、中国四大古橋の一つに数えられています。'),
  'chaozhou/woodcarving': ('潮州木彫', '金箔を施した幾重にも重なる精巧な木彫りが、寺院の空間を華やかに彩っています。'),
  'chaozhou/chaoxiu': ('潮州刺繍', '金糸を立体的に縫い上げる潮州刺繍は、中国南部で最も豪華絢爛な刺繍として知られています。'),
  'chaozhou/kaiyuan': ('開元寺', '1200年以上の歴史を持つこの寺院は、唐代の面影を残す静寂な境内で市民の心の拠り所となっています。'),
  'jieyang/citygate': ('進賢門', '川沿いに佇む優美な木造の城門は、かつての掲陽の姿を今に伝える貴重なシンボルです。'),
  'jieyang/jade': ('翡翠の都', '陽美地区は、中国最大級の翡翠の彫刻および取引拠点として広く知られています。'),
  'jieyang/jieyanglou': ('掲陽楼', '伝統的な屋根の様式を取り入れたこの巨大な塔は、潮汕文化を象徴する現代のモニュメントです。'),
  'jieyang/beefbroth': ('潮汕牛肉鍋', '新鮮な牛肉を澄んだスープでさっと湯通しして味わうこの料理は、この地域を代表する名物です。'),
  'yunfu/marble': ('石材の王国', '大理石や石材加工の中心地である雲浮は、磨き上げられた高品質な石材を世界中に輸出しています。'),
  'yunfu/patriarch': ('六祖恵能', '禅宗の祖師である恵能の生誕地であり、国恩寺は多くの参拝者が訪れる聖地となっています。'),
  'yunfu/tianlu': ('天露山', '雲に覆われた峰々と茶畑が広がる天露山は、街の自然を象徴する緑豊かな名山です。'),
  'yunfu/xijiang': ('西江', '中国南部を代表する大河であり、珠江の主要な支流としてこの街を流れています。'),
  'liuzhou/luosifen': ('螺蛳粉', '独特の香りと酸っぱ辛い味わいが特徴の「螺蛳粉（ルオスーフエン）」は、今や中国全土で大人気の麺料理です。'),
  'liuzhou/autocity': ('自動車の街', '柳州は市民に愛される小型車を中心に、中国有数の自動車生産拠点として知られています。'),
  'liuzhou/karst': ('柳江のカルスト地形', '街を囲むように流れる川と石灰岩の山々が、工業都市である柳州に美しい自然の景観をもたらしています。'),
  'liuzhou/liuhou': ('柳宗元', '唐代の詩人であり、この地の知事も務めた柳宗元を祀る廟が市内の公園にあり、今も人々に親しまれています。'),
  'wuzhou/gemstone': ('宝石の街', 'この川沿いの街にある工房では、世界中の人工宝石の多くが加工されています。'),
  'wuzhou/liubaotea': ('六堡茶', '熟成された黒茶である「六堡茶（りゅうほうちゃ）」は、湿度の高い南部で消化を助ける飲み物として古くから愛されています。'),
  'wuzhou/turtlejelly': ('亀苓膏', 'ほろ苦い黒い薬膳ゼリー「亀苓膏（きれいこう）」は、暑い日にぴったりの涼やかなデザートです。'),
  'wuzhou/dragonmother': ('龍母廟', '川の女神である龍母を祀るこの寺院は、古くから水辺で暮らす人々の信仰を集めてきました。'),
  'beihai/silverbeach': ('銀灘', 'きらめくような真っ白な砂浜がどこまでも続く、中国屈指の美しいビーチです。'),
  'beihai/pearl': ('真珠の街', '合浦の南洋真珠は、古くから皇帝への献上品として最高級の評価を受けてきました。'),
  'beihai/weizhou': ('潿洲島', '中国で最も新しい火山島であり、黒い断崖と美しいサンゴ礁がダイバーたちを魅了しています。'),
  'beihai/oldstreet': ('老街', '100年以上の歴史を持つコロニアル様式の建物が並び、かつての海上シルクロードの港町の面影を今に伝えています。'),
  'qinzhou/nixingpottery': ('坭興陶', '窯の中で自然に色が変化する「坭興陶（げいこうとう）」は、中国四大陶器の一つに数えられています。'),
  'qinzhou/dolphin': ('シナウスイロイルカ', '三娘湾に生息する希少なシナウスイロイルカは、この街のシンボルとして市民に愛されています。'),
  'qinzhou/oysterfarm': ('欽州の養殖カキ', '浅瀬の湾で育てられる巨大なカキは、欽州を中国有数のカキの産地として有名にしています。'),
  'qinzhou/general': ('馮子材将軍', '国境を守り抜いた老将軍、馮子材の故郷であり、その英雄的な功績が今も語り継がれています。'),
  'guigang/lotus': ('蓮の街', '夏の間、広大な蓮畑が一面に咲き誇ることから、貴港は「蓮の街」と呼ばれています。'),
  'guigang/uprising': ('金田蜂起', '歴史を大きく揺るがした太平天国の乱の火蓋が切られたのは、この地でのことでした。'),
  'guigang/nanshan': ('南山寺', '岩壁に刻まれた千年の歴史を持つ洞窟寺院で、皇帝による碑文が残されています。'),
  'guigang/sugarcane': ('サトウキビ', '肥沃な川沿いの平野は、中国最大の砂糖生産量を誇る甘い恵みの源です。'),
  'yulin/medicine': ('漢方薬市場', '中国南部最大規模の漢方薬市場であり、何千種類もの薬草が集まっています。'),
  'yulin/goldenpalace': ('雲天文化城', '黄金に輝く巨大な文化宮殿で、壮大な彫像や豪華な広間が訪れる人を圧倒します。'),
  'yulin/lychee': ('ライチ園', '温暖な丘陵地帯で育つ甘いライチは、夏の市場を彩る赤い宝石のような果物です。'),
  'yulin/beef': ('玉林牛肉', 'スパイスで味付けされた干し肉「牛巴」は、この地域で古くから親しまれている名物おやつです。'),
  'baise/redbase': ('百色蜂起', '若き日の鄧小平が率いたこの蜂起は、中国の革命史における重要な転換点となりました。'),
  'baise/sinkhole': ('楽業天坑群', '世界最大規模を誇る巨大な陥没穴群で、その深部には神秘的な森が広がっています。'),
  'baise/mango': ('マンゴーの都', '暑い谷あいの気候を活かした、中国最大のマンゴー栽培地として知られています。'),
  'baise/aluminum': ('アルミニウムの街', 'ボーキサイト資源が豊富なこの街は、中国南部のアルミニウム産業の拠点となっています。'),
  'hechi/longevity': ('巴馬の長寿村', '100歳を超える長寿者が多く暮らす巴馬は、世界的に有名な「長寿の郷」です。'),
  'hechi/folksong': ('劉三姐', '歌の妖精として知られる劉三姐の伝説は、今もなお掛け合い歌の文化として受け継がれています。'),
  'hechi/bronzedrum': ('銅鼓', 'チワン族や山岳民族にとって神聖な楽器である銅鼓が、この地には世界で最も多く集まっています。'),
  'hechi/geopark': ('カルストジオパーク', '巨大な陥没穴や洞窟、地下河川が広がるこの地域は、まさにカルスト地形のワンダーランドです。'),
  'laibin/sugarcity': ('砂糖の都', 'どこまでも続くサトウキビ畑が広がる来賓は、「中国の砂糖の都」と呼ばれています。'),
  'laibin/yao': ('大瑶山ヤオ族', '金秀の大瑶山に住むヤオ族は、5つの異なる支系からなる貴重な文化の宝庫です。'),
  'laibin/hongshui': ('紅水河', '雄大な紅水河が刻む渓谷は、ダムによる発電だけでなく、美しい景観でもこの地域を潤しています。'),
  'laibin/shengtang': ('聖堂山', '雲海と滝が織りなす絶景で知られるこの山は、大瑶山脈の最高峰です。'),
  'chongzuo/waterfall': ('徳天瀑布', 'ベトナムとの国境に位置する徳天瀑布は、アジア最大級の国境をまたぐ滝として有名です。'),
  'chongzuo/langur': ('フランソワルトン（白頭葉猴）', '石灰岩の山々にのみ生息する希少な白頭葉猴は、世界で最も絶滅が危惧されているサルの一種です。'),
  'chongzuo/rockart': ('花山岩画', '2000年前に左江の断崖に描かれた赤い人物画は、ユネスコ世界遺産にも登録されています。'),
  'chongzuo/borderpass': ('友誼関', 'ベトナムとの歴史的な国境門であり、南のシルクロードにおける重要な陸の玄関口です。'),
  'beijing/great-wall': ('万里の長城', '全長2万キロメートルを超える世界最長の防壁で、北京近郊の八達嶺は石段や見張り台が整備された最も有名な観光地です。'),
  'beijing/temple': ('天壇', '明・清の皇帝が豊作を祈った神聖な場所で、釘を一本も使わずに建てられた青い屋根の祈年殿は中国建築の象徴です。'),
  'beijing/pagoda': ('天寧寺塔', '遼代に建てられた高さ約57メートルの八角形のレンガ造りの塔で、北京で最も古い建造物の一つとして千年の歴史を見守っています。'),
  'beijing/opera': ('京劇', '歌や台詞、武術を融合させた200年の歴史を持つ伝統芸能で、顔に描かれた隈取（連譜）の色によって役柄の性格が表現されます。'),
  'zunyi/huiyi': ('遵義会議', '1935年に中国革命の運命を大きく変えた会議が開かれた場所であり、中国共産党の歴史における重要な転換点です。'),
  'zunyi/moutai': ('茅台鎮', '赤水河のほとりに位置するこの町で造られる「茅台酒」は、中国の国酒として世界的に有名な伝説の白酒です。'),
  'zunyi/loushan': ('婁山関', '険しい山々に囲まれたこの峠は、毛沢東の有名な詩にも詠まれた歴史的な激戦地として知られています。'),
  'zunyi/chishui': ('赤水大瀑布', '赤い丹霞地形の崖と竹林の間を流れ落ちる滝が、美しい「赤水」の渓谷を彩っています。'),
  'liupanshui/coolcity': ('涼都', '夏の平均気温が19度前後と非常に涼しいため、六盤水市は「中国の涼都」と呼ばれています。'),
  'liupanshui/coal': ('西南の炭海', '豊富な石炭資源に恵まれており、中国南西部におけるエネルギー供給の拠点となっています。'),
  'liupanshui/grassland': ('烏蒙大草原', '烏蒙高原に広がる果てしない草原には、放牧された馬の群れや風力発電の風車が点在しています。'),
  'liupanshui/kiwi': ('レッドキウイ', '冷涼な高原で栽培されるレッドキウイは、この街を代表する甘くて美味しい特産品です。'),
  'anshun/huangguoshu': ('黄果樹瀑布', 'アジア最大級の規模を誇るこの滝は、高さ77メートルから轟音を立てて流れ落ち、水しぶきで虹がかかることもあります。'),
  'anshun/dixi': ('地戯', '木製の仮面をつけた演者が村の広場で演じる地戯は、「中国演劇の生きた化石」と呼ばれています。'),
  'anshun/batik': ('ろうけつ染め', 'ブイ族やミャオ族の女性たちが蝋で模様を描き、藍で染め上げる伝統工芸品は安順の誇りです。'),
  'anshun/tunpu': ('屯堡村落', '明代の軍事拠点として築かれた石造りの村々で、600年前の服装や方言が今も大切に守られています。'),
  'bijie/azalea': ('百里杜鵑', '春になると山々を埋め尽くすツツジの花畑は、世界最大規模の天然の庭園として知られています。'),
  'bijie/zhijin': ('織金洞', '巨大な石筍が林立する「地下の宮殿」とも称される織金洞は、中国で最も壮大な鍾乳洞の一つです。'),
  'bijie/caohai': ('草海', '威寧にあるこの浅い湖は、冬になると希少なオグロヅルが飛来する越冬地として有名です。'),
  'bijie/potato': ('畢節のジャガイモ', '高地で栽培される畢節のジャガイモは中国の食糧庫として知られ、特に威寧産のものは全国的に有名です。'),
  'qujing/rapeseed': ('羅平の菜の花畑', '毎年2月になると、羅平の黄金色に輝く広大な菜の花畑には、養蜂家や写真家たちがこぞって訪れます。'),
  'qujing/ham': ('宣威ハム', '何世紀にもわたって塩漬けの伝統を守り続けてきた宣威ハムは、雲南料理を代表する誇り高き逸品です。'),
  'qujing/jiulong': ('九龍瀑布群', '「九龍」の名を冠する10段の階段状の滝は、中国で最も美しい滝の連なりとして知られています。'),
  'qujing/sandforest': ('彩色沙林', '陸良にある風に削られた色鮮やかな砂の柱は、まるで自然が作り出した彫刻庭園のようです。'),
  'yuxi/fuxian': ('撫仙湖', '中国で2番目の深さを誇るこの湖は、山々を映し出す鏡のように澄み切った水を湛えています。'),
  'yuxi/nieer': ('聶耳', '中国国歌の作曲家である聶耳の故郷であり、市内には彼を称える音楽公園や記念館が整備されています。'),
  'yuxi/chengjiang': ('澄江化石地', '5億3000万年前のカンブリア紀の化石群は、動物の起源を物語る世界遺産として登録されています。'),
  'yuxi/kiln': ('玉渓窯', '元代から続くこの古窯は、雲南における青花磁器発祥の地として知られています。'),
  'dali/threepagodas': ('崇聖寺三塔', '蒼山の麓に千年以上もそびえ立つ3つの優美な塔は、かつての大理国の象徴です。'),
  'dali/erhai': ('洱海', '耳の形をしたこの山岳湖は、漁船や湖畔の村々が織りなす絵画のような風景が広がっています。'),
  'dali/cangshan': ('蒼山', '19もの雪を頂いた峰々が連なる蒼山は、大理の街の背後に緑のカーテンのようにそびえ立っています。'),
  'dali/wind': ('風花雪月', '下関の風、上関の花、蒼山の雪、洱海の月という大理の4つの絶景は、詩のように美しく語り継がれています。'),
  'lijiang/oldtown': ('麗江古城', '運河と瓦屋根の木造家屋が織りなすこの世界遺産の街は、ナシ族文化が息づく中心地です。'),
  'lijiang/snowmountain': ('玉龍雪山', '標高5596メートルの氷河を抱く峰は、眠れる翡翠の龍のように街を見守っています。'),
  'lijiang/dongba': ('トンパ文字', 'ナシ族の聖職者が用いるトンパ文字は、世界で唯一現存する象形文字です。'),
  'lijiang/tigerleaping': ('虎跳峡', '虎がひと跳びで渡ったという伝説が残るこの峡谷は、世界でも有数の深い渓谷として知られています。'),
  'lincang/dianhong': ('滇紅', '鳳慶で生産される金色の芽を含んだ紅茶「滇紅」は、雲南省の名を世界に広めました。'),
  'lincang/wadrum': ('ワ族の木鼓', 'ワ族の神聖な木鼓は、髪を振り乱して踊る伝統的なダンスとともに山間の村々に響き渡ります。'),
  'lincang/teatrees': ('古茶樹', '臨滄は樹齢数千年の野生の茶樹が自生する、茶の起源を守り続ける地です。'),
  'lincang/lancang': ('瀾滄江', 'メコン川の上流にあたる瀾滄江は南へと流れ、巨大なダムによって流域の谷を照らしています。'),
  'puer/tea': ('プーアル茶', '熟成とともに味わい深くなる固形茶のプーアル茶は、この山間の都市の名を冠した生きた宝物です。'),
  'puer/coffee': ('中国のコーヒーの都', '中国のコーヒー生産量の半分以上を占めるプーアルの霧深い斜面は、街全体がコーヒーの香りに包まれています。'),
  'puer/teahorse': ('茶馬古道', 'プーアルを起点にチベットへと続く茶馬古道は、かつてラバの隊商が茶を運んだ雲上の交易路です。'),
  'puer/peafowl': ('インドクジャク', '希少なインドクジャクが棲息する熱帯の森は、この街が誇る野生の至宝です。'),
  'baoshan/volcano': ('騰衝火山群', '97もの休火山が連なる騰衝の平原は、まるで月面のような独特の景観を作り出しています。'),
  'baoshan/rehai': ('熱海', '沸き立つ「熱海」の谷では、間欠泉が湯気を上げ、温泉の熱で卵を茹でる光景が見られます。'),
  'baoshan/heshun': ('和順古鎮', '海外で活躍した商人たちの石造りの町である和順には、中国で最も古い村の図書館が残されています。'),
  'baoshan/gaoligong': ('高黎貢山', '蝶が舞う谷や温暖な森が広がる高黎貢山は、多様な生物の宝庫です。'),
  'deyang/sanxingdui': ('三星堆遺跡', '巨大な青銅の仮面が出土したことで、3000年前の謎に包まれた蜀文明の存在が明らかになりました。'),
  'deyang/jiannanchun': ('剣南春', '唐の時代から愛され、1500年もの歴史を持つ綿竹の銘酒です。'),
  'deyang/nianhua': ('綿竹年画', '手描きと木版画の技法で彩られた年画は、人々の願いを込めて玄関に飾られます。'),
  'deyang/turbine': ('重工業の都', '中国国内の巨大なタービンや発電設備の多くが、徳陽の工場で製造されています。'),
  'mianyang/libai': ('李白の故郷', '詩仙と称される李白が育った江油の山々には、今も彼の詩情が息づいています。'),
  'mianyang/sciencecity': ('科学城', '中国で唯一「科学技術城」の称号を持つこの街は、最先端の技術で未来を切り拓いています。'),
  'mianyang/qiang': ('羌族の石楼', '北川の山村には、羌族の人々が古くから守り続けてきた石造りの望楼がそびえ立っています。'),
  'mianyang/mifen': ('綿陽米粉', '鶏肉やホルモンの旨味が溶け込んだ熱々のスープで食べる米粉は、綿陽の朝に欠かせないソウルフードです。'),
  'nanchong/langzhong': ('閬中古城', '風水の教えに基づいて設計された、川に囲まれた美しい古都が今もそのままの姿で残っています。'),
  'nanchong/silk': ('シルクの都', '2000年以上の織物文化を誇る南充は、中国西部におけるシルク産業の中心地です。'),
  'nanchong/zhangfei': ('張飛牛肉', '三国志の英雄・張飛ゆかりの地で生まれた、スパイスの効いた干し牛肉です。'),
  'nanchong/zhude': ('朱徳の故郷', '儀隴にある朱徳元帥の質素な生家は、近代史を学ぶ人々が訪れる聖地となっています。'),
  'yibin/wuliangye': ('五糧液', '5種類の穀物を原料として醸造される、中国を代表する最高級の白酒です。'),
  'yibin/firstcity': ('長江第一城', '岷江と金沙江が合流して長江となる場所にあることから、宜賓は「長江第一城」と呼ばれています。'),
  'yibin/bamboosea': ('蜀南竹海', '120もの山々を覆い尽くす広大な竹林が、風に揺れて緑の海のように広がっています。'),
  'yibin/ranmian': ('燃麺', '油分が多く火がつくほどと言われる「燃麺」は、宜賓の朝を彩る刺激的な麺料理です。'),
  'luzhou/laojiao': ('瀘州老窖', '1573年から使い続けられている泥の醸造槽は、香り高い白酒の心臓部です。'),
  'luzhou/port': ('長江港', '二つの川が合流するこの港町は、四川省における海への水の玄関口となっています。'),
  'luzhou/longan': ('リュウガン（竜眼）', '温暖な川沿いの斜面で育つリュウガンは、「竜の目」と呼ばれる蜂蜜のように甘い果物です。'),
  'luzhou/umbrella': ('分水油紙傘', '分水の職人が手作りする油紙傘は、400年の歴史を持つ優美な伝統工芸品です。'),
  'leshan/giantbuddha': ('楽山大仏', '崖に彫られた高さ71メートルの座仏は、12世紀もの間、川の合流点を見守り続けています。'),
  'leshan/emei': ('峨眉山', '仏教の聖地の一つである峨眉山の金頂は、雲海の上に輝く絶景として知られています。'),
  'leshan/monkeys': ('峨眉山のサル', '登山道に住むいたずら好きなサルたちは、参拝者のバッグを大胆に漁ることで有名です。'),
  'leshan/qiaojiao': ('翹脚牛肉', '漢方薬とともに煮込まれた「翹脚牛肉」は、楽山の屋台で100年以上愛され続ける定番料理です。'),
  'zigong/saltwell': ('深海井', '世界で初めて深さ1000メートルを超えた深海井は、2000年の歴史を持つ塩の街の誇りです。'),
  'zigong/lantern': ('自貢灯会', '毎年旧正月になると、巨大で色鮮やかなランタンが街を幻想的な世界へと変貌させます。'),
  'zigong/dinosaur': ('自貢恐竜博物館', 'ジュラ紀の地層から発掘された数多くの化石が展示されており、自貢は「恐竜の都」と呼ばれています。'),
  'zigong/rabbit': ('冷兎', '四川省で最も刺激的な前菜の一つである「冷兎」は、この街を代表する冷製ウサギ肉料理です。'),
  'panzhihua/steel': ('バナジウム・チタンの都', '山間に築かれたこの巨大な鉄鋼都市では、世界有数のバナジウムとチタンの鉱床が採掘されています。'),
  'panzhihua/fruitvalley': ('陽光果物谷', '乾燥した熱い谷間で育つマンゴーやザクロは、冬でも太陽の光を浴びて完熟します。'),
  'panzhihua/sunshine': ('冬の陽光都市', '年間2700時間もの日照時間を誇る攀枝花は、穏やかな冬を過ごすための保養地として人気です。'),
  'panzhihua/jinsha': ('金沙江', '黄金の砂をたたえた金沙江が街を流れ、深い渓谷を刻み込んでいます。'),
  'dazhou/gas': ('天然ガスの都', '巨大な普光ガス田を擁する達州は、中国の天然ガスエネルギー供給の拠点となっています。'),
  'dazhou/ba': ('巴国の遺産', '柳葉刀を操った古代巴国の戦士たちの歴史が、羅家壩遺跡を通じて今に伝わっています。'),
  'dazhou/dengying': ('灯影牛肉', '光に透けるほど薄くスライスされたスパイシーな牛肉で、その名は影絵芝居に由来しています。'),
  'dazhou/hanque': ('漢闕', '渠県にある2000年の歴史を持つ石造りの門「漢闕」は、漢代建築の優美さを今に伝える貴重な遺構です。'),
  'guangyuan/jianmen': ('剣門関', '「一夫関に当たれば万夫も開くこと能わず」と称される剣門関は、蜀の道を守る要衝です。'),
  'guangyuan/wuzetian': ('武則天の生誕地', '中国史上唯一の女帝・武則天の生誕地であり、皇澤寺では千年にわたり彼女の功績を称えています。'),
  'guangyuan/plankroad': ('古桟道', '断崖絶壁に打ち付けられた桟道は、「蜀の道は天に登るより難し」と言われた当時の人々の挑戦の証です。'),
  'guangyuan/cypress': ('翠雲廊', '三国時代から続く数万本の古柏が、古い街道を緑のトンネルのように覆っています。'),
  'yaan/panda': ('パンダの故郷', '1869年に宝興で初めて科学的に記録されたジャイアントパンダの歴史を、碧峰峡パンダ基地が今に伝えています。'),
  'yaan/rain': ('雨の街', '毎晩のように降る「雅雨」が屋根を洗い、街全体が鮮やかな緑色に輝いています。'),
  'yaan/mengding': ('蒙頂山茶', '2000年前に世界で初めて人工栽培が行われたとされる蒙頂山は、茶文化発祥の地として知られています。'),
  'yaan/yayu': ('雅魚', '雪解け水で育つ伝説の魚「雅魚」は、この街の誇りであり、鍋料理として親しまれています。'),
  'xianyang/qincapital': ('秦の都', '中国を初めて統一した秦の都が置かれた場所であり、咸陽は帝国への道を切り拓く中心地でした。'),
  'xianyang/qianling': ('乾陵', '武則天とその夫が共に眠るこの山陵は、歴史の謎を秘めた無字碑で有名です。'),
  'xianyang/zhengguo': ('鄭国渠', '2000年以上の歴史を持つこの灌漑用水路は、関中平原を秦の穀倉地帯へと変貌させました。'),
  'xianyang/guokui': ('鍋魁', '鍋の蓋ほどの大きさがある香ばしい「鍋魁」は、陝西省で何世紀にもわたって親しまれてきた伝統的な軽食です。'),
  'baoji/bronze': ('青銅器の都', '宝鶏からは「中国」という文字が初めて刻まれた「何尊」をはじめ、数千点もの周代の青銅器が出土しています。'),
  'baoji/famen': ('法門寺', '仏の指の骨（仏指舎利）を祀る法門寺は、唐の皇帝たちにとって神聖な宝庫でした。'),
  'baoji/taibai': ('太白山', '秦嶺山脈の最高峰である標高3771メートルの太白山は、夏でも雪が残る頂として数々の伝説を伝えています。'),
  'baoji/saozi': ('臊子麺', '酸味と辛味の効いた肉ソースで味わう岐山県の「臊子麺」は、3000年前の周代から続く伝統の味です。'),
};
